import "@openzeppelin/contracts/token/ERC721/IERC721.sol";
import "@chainlink/contracts/src/v0.8/VRFConsumerBase.sol";

contract RedeemContract is VRFConsumerBase {
    bytes32 internal keyHash;
    uint256 internal fee;
    address public nftAddress;
    bool public locked;
    uint256 public unlockTime;
    mapping(address => bool) public nftOwners;
    mapping(bytes32 => address) public requestIdToSender;
    mapping(bytes32 => uint256) public requestIdToRandomNumber;

    event Redeem(address indexed user, uint256 tokenId, uint256 randomNumber);
    event Claim(address indexed user, uint256 tokenId);

    constructor(
        address _vrfCoordinator,
        address _linkToken,
        bytes32 _keyHash,
        uint256 _fee,
        address _nftAddress
    ) VRFConsumerBase(_vrfCoordinator, _linkToken) {
        keyHash = _keyHash;
        fee = _fee;
        nftAddress = _nftAddress;
        locked = true;
        unlockTime = block.timestamp + 1 weeks; // Set initial lock period
    }

    modifier onlyUnlocked() {
        require(!locked || block.timestamp >= unlockTime, "Contract is still locked");
        _;
    }

    function claimSC(uint256[] calldata tokenIds) external onlyUnlocked {
        IERC721 nft = IERC721(nftAddress);
        for (uint256 i = 0; i < tokenIds.length; i++) {
            require(nft.ownerOf(tokenIds[i]) == msg.sender, "Not owner of token");
            nftOwners[msg.sender] = true;
            bytes32 requestId = requestRandomness(keyHash, fee);
            requestIdToSender[requestId] = msg.sender;
            requestIdToRandomNumber[requestId] = 0;
        }
    }

    function process(bytes32 requestId, uint256 randomness) external override onlyOwner {
        require(requestIdToSender[requestId] != address(0), "Invalid requestId");
        address sender = requestIdToSender[requestId];
        requestIdToRandomNumber[requestId] = randomness;
        emit Redeem(sender, 0, randomness); // TokenId placeholder
        mintNFT(sender, randomness);
    }

    function claim(uint256[] calldata tokenIds) external {
        IERC721 nft = IERC721(nftAddress);
        for (uint256 i = 0; i < tokenIds.length; i++) {
            require(nft.ownerOf(tokenIds[i]) == msg.sender, "Not owner of token");
            require(nftOwners[msg.sender], "User has not claimed before");
            nft.transferFrom(msg.sender, address(this), tokenIds[i]);
            emit Claim(msg.sender, tokenIds[i]);
        }
    }

